import { useLocation } from "react-router-dom";
import "./styles/Dashboard.css";

function StudentDashboard() {
  const location = useLocation();
  const name = location.state?.name || "Student";

  return (
    <div className="dashboard-page">
      <h1 className="dashboard-title">Welcome, {name}</h1>

      <div className="dashboard-row">
        <div className="dash-card">📚 My Borrowed Books</div>
        <div className="dash-card">🕘 History by Category</div>
        <div className="dash-card">🔎 Explore Library</div>
        <div className="dash-card">❤️ Wishlist</div>
      </div>
    </div>
  );
}

export default StudentDashboard;
